const now = new Date().toISOString();

const registry = {
  registry_version: "1.0.0",
  source: "OSA Registry Loader",
  assets: [
    { asset_id: "OSA.KERNEL.GATEWAY.001", legacy_alias: ["OSA-KERNEL-001"], status: "active", asset_type: "kernel", dependencies: [] },
    { asset_id: "OSA.KERNEL.CREDENTIAL_VAULT.001", legacy_alias: ["OSA-KERNEL-002"], status: "active", asset_type: "kernel", dependencies: [] },
    { asset_id: "OSA.KERNEL.LOGGER.001", legacy_alias: ["OSA-KERNEL-003"], status: "active", asset_type: "kernel", dependencies: [] },
    { asset_id: "OSA.KERNEL.REGISTRY.001", legacy_alias: ["OSA-KERNEL-004"], status: "active", asset_type: "kernel", dependencies: [] },
    { asset_id: "OSA.KERNEL.HEALTH_MONITOR.001", legacy_alias: ["OSA-KERNEL-005"], status: "active", asset_type: "kernel", dependencies: [] },
    { asset_id: "AI5R.PLATFORM.MEMORY.001", legacy_alias: ["AI5R-MEMORY"], status: "active", asset_type: "platform", dependencies: ["OSA.KERNEL.REGISTRY.001", "OSA.KERNEL.LOGGER.001"] },
    { asset_id: "AI5R.PLATFORM.GIT.001", legacy_alias: ["AI5R-GIT"], status: "active", asset_type: "platform", dependencies: ["OSA.KERNEL.GATEWAY.001", "OSA.KERNEL.LOGGER.001"] },
    { asset_id: "AI5R.PLATFORM.ARTIFACT.001", legacy_alias: ["AI5R-ARTIFACT"], status: "active", asset_type: "platform", dependencies: ["AI5R.PLATFORM.MEMORY.001", "AI5R.PLATFORM.GIT.001"] }
  ]
};

const assetMap = Object.fromEntries(registry.assets.map(a => [a.asset_id, a]));
const errors = [];

for (const asset of registry.assets) {
  for (const dep of asset.dependencies || []) {
    if (!assetMap[dep]) {
      errors.push(`Missing dependency ${dep} for ${asset.asset_id}`);
    }
  }
}

const modules = registry.assets.map(asset => ({
  asset_id: asset.asset_id,
  legacy_alias: asset.legacy_alias || [],
  asset_type: asset.asset_type,
  status: asset.status,
  dependencies: asset.dependencies || []
}));

return [{
  json: {
    success: errors.length === 0,
    product: "OSA",
    service: "OSA-REGISTRY-LOADER-001",
    status: errors.length ? "DEGRADED" : "READY",
    loaded_at: now,
    registry_version: registry.registry_version,
    modules_count: modules.length,
    modules,
    errors
  }
}];
